#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <float.h>

#include "kmeans.h"

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

__device__ float euclid_dist_2_device(float *pt1, float *pt2, int numdims) {
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

__device__ int find_nearest_point_device(float *pt, int nfeatures, float **pts, int npts) {
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < npts; i++) {
        float dist = euclid_dist_2_device(pt, pts[i], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

__global__ void kmeans_iter_kernel(
    float **feature,
    float **clusters,
    int *membership,
    int *new_centers_len,
    float *new_centers_data,
    int npoints,
    int nclusters,
    int nfeatures,
    float *delta_ptr
) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= npoints) return;

    int index = find_nearest_point_device(feature[i], nfeatures, clusters, nclusters);

    if (membership[i] != index) {
        atomicAdd(delta_ptr, 1.0f);
    }

    membership[i] = index;

    atomicAdd(&new_centers_len[index], 1);

    for (int j = 0; j < nfeatures; j++) {
        float val = feature[i][j];
        int offset = index * nfeatures + j;
        atomicAdd(&new_centers_data[offset], val);
    }
}

float** kmeans_clustering(float **feature,    
                          int     nfeatures,
                          int     npoints,
                          int     nclusters,
                          float   threshold,
                          int    *membership) 
{
    int      i, j, n=0, loop=0;
    int     *new_centers_len_host;			
    float  **new_centers_host;				
    float  **clusters;					
    float    delta;

    new_centers_len_host = (int*) calloc(nclusters, sizeof(int));
    new_centers_host    = (float**) malloc(nclusters * sizeof(float*));
    new_centers_host[0] = (float*)  calloc(nclusters * nfeatures, sizeof(float));
    for (i=1; i<nclusters; i++)
        new_centers_host[i] = new_centers_host[i-1] + nfeatures;

    clusters    = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*)  malloc(nclusters * nfeatures * sizeof(float));
    for (i=1; i<nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    for (i=0; i<nclusters; i++) {
        for (j=0; j<nfeatures; j++)
            clusters[i][j] = feature[n][j];
        n++;
    }

    for (i=0; i<npoints; i++)
        membership[i] = -1;

    // CUDA Setup
    float **d_feature;
    float **d_feature_ptrs;
    float **d_clusters;
    float **d_clusters_ptrs;
    int *d_membership;
    int *d_new_centers_len;
    float *d_new_centers_data;
    float *d_delta;

    cudaMalloc(&d_feature_ptrs, npoints * sizeof(float*));
    for (i=0; i<npoints; i++) {
        cudaMalloc(&d_feature_ptrs[i], nfeatures * sizeof(float));
        cudaMemcpy(d_feature_ptrs[i], feature[i], nfeatures * sizeof(float), cudaMemcpyHostToDevice);
    }
    cudaMalloc(&d_feature, npoints * sizeof(float*));
    cudaMemcpy(d_feature, d_feature_ptrs, npoints * sizeof(float*), cudaMemcpyHostToDevice);

    cudaMalloc(&d_clusters_ptrs, nclusters * sizeof(float*));
    for (i=0; i<nclusters; i++) {
        cudaMalloc(&d_clusters_ptrs[i], nfeatures * sizeof(float));
        cudaMemcpy(d_clusters_ptrs[i], clusters[i], nfeatures * sizeof(float), cudaMemcpyHostToDevice);
    }
    cudaMalloc(&d_clusters, nclusters * sizeof(float*));
    cudaMemcpy(d_clusters, d_clusters_ptrs, nclusters * sizeof(float*), cudaMemcpyHostToDevice);

    cudaMalloc(&d_membership, npoints * sizeof(int));
    cudaMalloc(&d_new_centers_len, nclusters * sizeof(int));
    cudaMalloc(&d_new_centers_data, nclusters * nfeatures * sizeof(float));
    cudaMalloc(&d_delta, sizeof(float));

    int blockSize = 256;
    int numBlocks = (npoints + blockSize - 1) / blockSize;

    do {
        delta = 0.0;
        cudaMemcpy(d_delta, &delta, sizeof(float), cudaMemcpyHostToDevice);
        cudaMemset(d_new_centers_len, 0, nclusters * sizeof(int));
        cudaMemset(d_new_centers_data, 0, nclusters * nfeatures * sizeof(float));

        kmeans_iter_kernel<<<numBlocks, blockSize>>>(
            d_feature,
            d_clusters,
            d_membership,
            d_new_centers_len,
            d_new_centers_data,
            npoints,
            nclusters,
            nfeatures,
            d_delta
        );
        cudaDeviceSynchronize();

        cudaMemcpy(&delta, d_delta, sizeof(float), cudaMemcpyDeviceToHost);
        cudaMemcpy(membership, d_membership, npoints * sizeof(int), cudaMemcpyDeviceToHost);
        cudaMemcpy(new_centers_len_host, d_new_centers_len, nclusters * sizeof(int), cudaMemcpyDeviceToHost);
        cudaMemcpy(new_centers_host[0], d_new_centers_data, nclusters * nfeatures * sizeof(float), cudaMemcpyDeviceToHost);

        // Update clusters
        for (i=0; i<nclusters; i++) {
            for (j=0; j<nfeatures; j++) {
                if (new_centers_len_host[i] > 0)
                    clusters[i][j] = new_centers_host[i][j] / new_centers_len_host[i];
                new_centers_host[i][j] = 0.0;   
            }
            new_centers_len_host[i] = 0;   
        }

        // Update device clusters for next iteration
        for (i=0; i<nclusters; i++) {
            cudaMemcpy(d_clusters_ptrs[i], clusters[i], nfeatures * sizeof(float), cudaMemcpyHostToDevice);
        }
        cudaMemcpy(d_clusters, d_clusters_ptrs, nclusters * sizeof(float*), cudaMemcpyHostToDevice);

    } while (delta > threshold && loop++ < 500);

    // Cleanup
    cudaFree(d_feature);
    cudaFree(d_feature_ptrs);
    cudaFree(d_clusters);
    cudaFree(d_clusters_ptrs);
    cudaFree(d_membership);
    cudaFree(d_new_centers_len);
    cudaFree(d_new_centers_data);
    cudaFree(d_delta);

    free(new_centers_host[0]);
    free(new_centers_host);
    free(new_centers_len_host);

    return clusters;
}

int cluster(int      numObjects,      
            int      numAttributes,   
            float  **attributes,                  
            int      nclusters,
            float    threshold,       
            float ***cluster_centres) 
{
    int    *membership;
    float **tmp_cluster_centres;

    membership = (int*) malloc(numObjects * sizeof(int));

    srand(7);

    tmp_cluster_centres = kmeans_clustering(attributes,
                                            numAttributes,
                                            numObjects,
                                            nclusters,
                                            threshold,
                                            membership);      

    if (*cluster_centres) {
		free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;

    free(membership);

    return 0;
}

